// The postcondition (set equality ==> vec equality) is fundamentally unprovable:
    // Two Vec<EndPoint> with the same .map_values(...).to_set() can have different
    // orderings, so Vec equality cannot be derived. Best-effort: prove the bridge
    // step that holds (set equality of the two views).
    if r1@.map_values(|e: EndPoint| e@).to_set() == self_@.dom()
        && r2@.map_values(|e: EndPoint| e@).to_set() == self_@.dom() {
        assert(r1@.map_values(|e: EndPoint| e@).to_set()
               == r2@.map_values(|e: EndPoint| e@).to_set());
    }
